namespace CodexTrafficLightWin {
internal static class Program {
  [STAThread] static int Main(string[] args) {
    try {
      string exe=Path.GetFileNameWithoutExtension(Application.ExecutablePath).ToLowerInvariant();
      if(exe.Contains("hook")) return HookCommand.Run(args);
      if(exe.Contains("codex-light-mxp")) return LightCommand.Run(args);
      bool createdNew=false; using(var mutex=new Mutex(true,"Global\\CodexTrafficLightMXP_RedGreenLight",out createdNew)){if(!createdNew)return 0;Application.EnableVisualStyles(); Application.SetCompatibleTextRenderingDefault(false);Application.Run(new TrafficLightApp());} return 0;
    } catch(Exception ex) { Console.Error.WriteLine(ex.Message); Log.Append("windows-error.log", ex.ToString()); return 2; }
  }
}

enum LightState { idle, working, done, waiting, quit }
static class StateText {
  public static string Label(LightState s) { switch(s){case LightState.working:return "正在干活";case LightState.done:return "可以验收";case LightState.waiting:return "等你回复";case LightState.quit:return "退出";default:return "空闲";} }
}
class TaskState { public LightState State; public string Workspace, Source, HookEventName, Message; public DateTime UpdatedAt; }
class QuotaSnapshot { public int FiveHourRemainingPercent, WeeklyRemainingPercent; public string Source; public DateTime UpdatedAt; }
class StateSnapshot { public LightState AggregateState=LightState.idle; public DateTime UpdatedAt=DateTime.UtcNow; public QuotaSnapshot Quota; public Dictionary<string,TaskState> Tasks=new Dictionary<string,TaskState>(); }
static class Defaults {
  public static double DoneSeconds { get { return Env("CODEX_LIGHT_DONE_IDLE_SECONDS",600); } }
  public static double WaitingSeconds { get { return Env("CODEX_LIGHT_WAITING_ALERT_SECONDS",10); } }
  public static int DoneFlashMs { get { return (int)(Env("CODEX_LIGHT_DONE_FLASH_SECONDS",1.4)*1000); } }
  public static int QuotaRefreshMs { get { return (int)(Env("CODEX_LIGHT_APP_SERVER_QUOTA_REFRESH_SECONDS",300)*1000); } }
  public static double SessionWaitingSeconds { get { return Env("CODEX_LIGHT_SESSION_WAITING_SECONDS",600); } }
  static double Env(string k,double f){double v;return double.TryParse(Environment.GetEnvironmentVariable(k),out v)&&v>0?v:f;}
}
class StateStore {
  public readonly string StatePath; JavaScriptSerializer json=new JavaScriptSerializer();
  public StateStore(string p=null){StatePath=p??DefaultStatePath();}
  public static string SupportDir(){return Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),"CodexTrafficLight");}
  public static string DefaultStatePath(){string o=Environment.GetEnvironmentVariable("CODEX_TRAFFIC_LIGHT_STATE_PATH");return string.IsNullOrWhiteSpace(o)?Path.Combine(SupportDir(),"state.json"):o;}
  public StateSnapshot Read(){try{if(!File.Exists(StatePath))return new StateSnapshot();return Prune(FromDict(json.Deserialize<Dictionary<string,object>>(File.ReadAllText(StatePath,Encoding.UTF8))));}catch{return new StateSnapshot();}}
  public StateSnapshot UpdateTask(string id,LightState state,string workspace,string source,string hook,string message){var s=Prune(Read());var now=DateTime.UtcNow;if(state==LightState.idle)s.Tasks.Remove(id);else if(state==LightState.quit){s.AggregateState=LightState.quit;s.UpdatedAt=now;Write(s);return s;}else s.Tasks[id]=new TaskState{State=state,Workspace=workspace,Source=source,HookEventName=hook,Message=message,UpdatedAt=now};s.AggregateState=Aggregate(s);s.UpdatedAt=now;Write(s);return s;}
  public StateSnapshot Clear(){var cur=Read();var s=new StateSnapshot{AggregateState=LightState.idle,UpdatedAt=DateTime.UtcNow,Quota=cur.Quota,Tasks=new Dictionary<string,TaskState>()};Write(s);return s;}
  public StateSnapshot UpdateQuota(int five,int week,string source){var s=Prune(Read());s.Quota=new QuotaSnapshot{FiveHourRemainingPercent=Clamp(five),WeeklyRemainingPercent=Clamp(week),Source=source,UpdatedAt=DateTime.UtcNow};s.AggregateState=Aggregate(s);s.UpdatedAt=DateTime.UtcNow;Write(s);return s;}
  public void Write(StateSnapshot s){Directory.CreateDirectory(Path.GetDirectoryName(StatePath));string tmp=StatePath+".tmp";File.WriteAllText(tmp,ToJson(s),Encoding.UTF8);if(File.Exists(StatePath))File.Delete(StatePath);File.Move(tmp,StatePath);} 
  public static LightState Aggregate(StateSnapshot s){foreach(var t in s.Tasks.Values)if(t.State==LightState.waiting)return LightState.waiting;foreach(var t in s.Tasks.Values)if(t.State==LightState.working)return LightState.working;var now=DateTime.UtcNow;foreach(var t in s.Tasks.Values)if(t.State==LightState.done&&(now-t.UpdatedAt).TotalSeconds<=Defaults.DoneSeconds)return LightState.done;return LightState.idle;}
  public static StateSnapshot Prune(StateSnapshot s){if(s.AggregateState==LightState.quit)return s;var now=DateTime.UtcNow;var kept=new Dictionary<string,TaskState>();foreach(var p in s.Tasks){var age=(now-p.Value.UpdatedAt).TotalSeconds;if(p.Value.State==LightState.done&&age>Defaults.DoneSeconds)continue;if(p.Value.State==LightState.waiting&&(p.Value.Source=="session"||p.Value.Source=="cli"||p.Value.Source=="menu")&&age>Defaults.SessionWaitingSeconds)continue;kept[p.Key]=p.Value;}s.Tasks=kept;s.AggregateState=Aggregate(s);return s;}
  public string ToJson(StateSnapshot s){return json.Serialize(ToDict(s));}
  StateSnapshot FromDict(Dictionary<string,object> r){var s=new StateSnapshot();object v;if(r==null)return s;if(r.TryGetValue("aggregate_state",out v))s.AggregateState=ParseState(Convert.ToString(v));if(r.TryGetValue("updated_at",out v))s.UpdatedAt=FromUnix(v);if(r.TryGetValue("quota",out v))s.Quota=ParseQuota(v as Dictionary<string,object>);if(r.TryGetValue("tasks",out v)){var d=v as Dictionary<string,object>;if(d!=null)foreach(var p in d){var t=ParseTask(p.Value as Dictionary<string,object>);if(t!=null)s.Tasks[p.Key]=t;}}return s;}
  Dictionary<string,object> ToDict(StateSnapshot s){var r=new Dictionary<string,object>{{"aggregate_state",s.AggregateState.ToString()},{"updated_at",ToUnix(s.UpdatedAt)}};if(s.Quota!=null)r["quota"]=new Dictionary<string,object>{{"five_hour_remaining_percent",s.Quota.FiveHourRemainingPercent},{"weekly_remaining_percent",s.Quota.WeeklyRemainingPercent},{"source",s.Quota.Source},{"updated_at",ToUnix(s.Quota.UpdatedAt)}};var tasks=new Dictionary<string,object>();foreach(var p in s.Tasks){var t=p.Value;tasks[p.Key]=new Dictionary<string,object>{{"state",t.State.ToString()},{"workspace",t.Workspace},{"source",t.Source},{"hook_event_name",t.HookEventName},{"message",t.Message},{"updated_at",ToUnix(t.UpdatedAt)}};}r["tasks"]=tasks;return r;}
  static TaskState ParseTask(Dictionary<string,object>d){if(d==null)return null;object v;return new TaskState{State=d.TryGetValue("state",out v)?ParseState(Convert.ToString(v)):LightState.idle,Workspace=d.TryGetValue("workspace",out v)?Convert.ToString(v):null,Source=d.TryGetValue("source",out v)?Convert.ToString(v):null,HookEventName=d.TryGetValue("hook_event_name",out v)?Convert.ToString(v):null,Message=d.TryGetValue("message",out v)?Convert.ToString(v):null,UpdatedAt=d.TryGetValue("updated_at",out v)?FromUnix(v):DateTime.UtcNow};}
  static QuotaSnapshot ParseQuota(Dictionary<string,object>d){if(d==null)return null;object v;return new QuotaSnapshot{FiveHourRemainingPercent=d.TryGetValue("five_hour_remaining_percent",out v)?Clamp(ToInt(v)):0,WeeklyRemainingPercent=d.TryGetValue("weekly_remaining_percent",out v)?Clamp(ToInt(v)):0,Source=d.TryGetValue("source",out v)?Convert.ToString(v):null,UpdatedAt=d.TryGetValue("updated_at",out v)?FromUnix(v):DateTime.UtcNow};}
  public static LightState ParseState(string raw){LightState s;return Enum.TryParse(raw,out s)?s:LightState.idle;} static int Clamp(int v){return Math.Max(0,Math.Min(100,v));} static int ToInt(object v){return Convert.ToInt32(Math.Round(Convert.ToDouble(v)));} static DateTime FromUnix(object v){return new DateTime(1970,1,1,0,0,0,DateTimeKind.Utc).AddSeconds(Convert.ToDouble(v));} static double ToUnix(DateTime d){return (d.ToUniversalTime()-new DateTime(1970,1,1,0,0,0,DateTimeKind.Utc)).TotalSeconds;}
}
class CliOptions { public string TaskId,Workspace,Command; public bool Json,Stdin,AppServer; public int? FiveHour,Weekly; public static CliOptions Parse(string[] a){var o=new CliOptions();for(int i=0;i<a.Length;i++){string x=a[i];if(x=="--task")o.TaskId=a[++i];else if(x=="--workspace")o.Workspace=a[++i];else if(x=="--json")o.Json=true;else if(x=="--stdin")o.Stdin=true;else if(x=="--app-server")o.AppServer=true;else if(x=="--five-hour")o.FiveHour=int.Parse(a[++i]);else if(x=="--weekly")o.Weekly=int.Parse(a[++i]);else if(o.Command==null)o.Command=x;else throw new Exception("too many commands");}return o;} }
static class LightCommand {
  public static int Run(string[] args){var o=CliOptions.Parse(args);if(o.Command==null){Usage();return 2;}var st=new StateStore();StateSnapshot s;switch(o.Command){case "status":s=st.Read();Print(s,st,o.Json);return 0;case "clear":s=st.Clear();Print(s,st,o.Json);return 0;case "quota":return Quota(o,st);case "quit":s=st.UpdateTask(TaskId(o),LightState.quit,Workspace(o),"cli",null,"Codex traffic light: quit");Print(s,st,o.Json);return 0;default:var state=StateStore.ParseState(o.Command);if(state==LightState.quit&&o.Command!="quit")throw new Exception("Unknown state: "+o.Command);s=st.UpdateTask(TaskId(o),state,Workspace(o),"cli",null,"Codex traffic light: "+state);Print(s,st,o.Json);return 0;}}
  static int Quota(CliOptions o,StateStore st){StateSnapshot s;if(o.AppServer){try{var q=CodexAppServerQuotaCollector.FetchQuota();s=st.UpdateQuota(q.FiveHour,q.Weekly,"codex-app-server");Print(s,st,o.Json);return 0;}catch(Exception ex){Log.Append("quota-mxp.log","quota app-server failed: "+ex.Message);Console.Error.WriteLine(ex.Message);return 2;}}if(o.Stdin){var q=QuotaExtractor.Extract(Console.In.ReadToEnd());if(q==null)throw new Exception("quota --stdin requires JSON with five-hour and weekly remaining percent");s=st.UpdateQuota(q.FiveHour,q.Weekly,"cli");Print(s,st,o.Json);return 0;}if(o.FiveHour.HasValue&&o.Weekly.HasValue){s=st.UpdateQuota(o.FiveHour.Value,o.Weekly.Value,"cli");Print(s,st,o.Json);return 0;}throw new Exception("quota requires --app-server, --stdin, or --five-hour + --weekly");}
  static string Workspace(CliOptions o){return o.Workspace??Environment.CurrentDirectory;} static string TaskId(CliOptions o){return o.TaskId??ContextResolver.TaskId(Workspace(o),null,null);} static void Print(StateSnapshot s,StateStore st,bool json){Console.OutputEncoding=Encoding.UTF8;Console.WriteLine(json?st.ToJson(s):s.AggregateState.ToString());}
  static void Usage(){Console.Error.WriteLine("Usage: codex-light-mxp [--task <id>] [--workspace <path>] [--json] <working|done|waiting|idle|status|clear|quit>");Console.Error.WriteLine("       codex-light-mxp quota --app-server|--stdin|--five-hour <0-100> --weekly <0-100> [--json]");}
}
class HookEvent { public string Name,LastAssistantMessage,Cwd,Workspace,SessionId,ThreadId; public static HookEvent Parse(string text,string fallback){var e=new HookEvent{Name=fallback};try{var d=new JavaScriptSerializer().Deserialize<Dictionary<string,object>>(text);e.Name=Get(d,"hook_event_name")??fallback;e.LastAssistantMessage=Get(d,"last_assistant_message");e.Cwd=Get(d,"cwd")??Get(d,"current_dir");e.Workspace=Get(d,"workspace")??Get(d,"workspace_root");e.SessionId=Get(d,"session_id")??Get(d,"conversation_id");e.ThreadId=Get(d,"thread_id")??Get(d,"turn_id");}catch{}return e;} static string Get(Dictionary<string,object>d,string k){object v;if(d!=null&&d.TryGetValue(k,out v)&&v!=null){string s=Convert.ToString(v);return string.IsNullOrWhiteSpace(s)?null:s;}return null;} }
static class HookCommand { public static int Run(string[] args){string input=Console.In.ReadToEnd();var ev=HookEvent.Parse(input,args.Length>0?args[0]:"");var st=new StateStore();try{var quota=QuotaExtractor.Extract(input);if(quota!=null){st.UpdateQuota(quota.FiveHour,quota.Weekly,"hook");if(HookMapper.IsQuotaOnlyEvent(ev.Name)){Log.Append("hook-mxp.log","event="+ev.Name+" state=quota result=ok quota="+quota.FiveHour+"/"+quota.Weekly);return 0;}}var state=HookMapper.StateFor(ev);string ws=ev.Workspace??ev.Cwd??Environment.CurrentDirectory;string id=ContextResolver.TaskId(ws,ev.SessionId,ev.ThreadId);var snap=st.UpdateTask(id,state,ws,"hook",ev.Name,"Codex traffic light: "+state);Log.Append("hook-mxp.log","event="+ev.Name+" state="+state+" task="+id+" result=ok aggregate="+snap.AggregateState);return 0;}catch(Exception ex){Log.Append("hook-mxp.log","event="+ev.Name+" result=error "+ex.Message);Console.Error.WriteLine(ex.Message);return 2;}} }
static class HookMapper { public static bool IsQuotaOnlyEvent(string n){return n=="RateLimitsUpdated"||n=="account/rateLimits/updated"||n=="AccountRateLimitsUpdated";} public static LightState StateFor(HookEvent e){switch(e.Name){case "UserPromptSubmit":case "PreToolUse":return LightState.working;case "PermissionRequest":return LightState.waiting;case "Stop":case "SubagentStop":return LooksWaiting(e.LastAssistantMessage)?LightState.waiting:LightState.done;default:return LightState.idle;}} public static bool LooksWaiting(string m){if(string.IsNullOrWhiteSpace(m))return false;string[] p={"等你","需要.{0,20}(回复|确认|授权|登录|验证码|文件|截图|选择|提供|补充)","请.{0,20}(回复|确认|授权|登录|提供|发我|补充|选择)","你.{0,20}(确认|选择|提供|发我|补充)","要不要|可以吗|行不行|是否","我需要.{0,20}(你|确认|授权|文件|截图|验证码)","blocked|waiting for user|permission|approval","\\?","？"};foreach(var x in p)if(Regex.IsMatch(m,x,RegexOptions.IgnoreCase))return true;return false;} }
class QuotaValues { public int FiveHour,Weekly; }
static class QuotaExtractor { public static QuotaValues Extract(string text){if(string.IsNullOrWhiteSpace(text))return null;try{return ExtractObj(new JavaScriptSerializer().DeserializeObject(text));}catch{return null;}} static QuotaValues ExtractObj(object obj){var d=obj as Dictionary<string,object>;if(d!=null){int? f=First(d,"five_hour_remaining_percent","fiveHourRemainingPercent"),w=First(d,"weekly_remaining_percent","weeklyRemainingPercent");if(f.HasValue&&w.HasValue)return new QuotaValues{FiveHour=Clamp(f.Value),Weekly=Clamp(w.Value)};foreach(string k in new[]{"quota","rate_limits","rateLimits"}){object c;if(d.TryGetValue(k,out c)){var q=ExtractObj(c);if(q!=null)return q;}}foreach(var c in d.Values){var q=ExtractObj(c);if(q!=null)return q;}}var a=obj as object[];if(a!=null)foreach(var c in a){var q=ExtractObj(c);if(q!=null)return q;}return null;} static int? First(Dictionary<string,object>d,params string[] keys){foreach(var k in keys){object v;if(d.TryGetValue(k,out v))return Convert.ToInt32(Math.Round(Convert.ToDouble(v)));}return null;} static int Clamp(int v){return Math.Max(0,Math.Min(100,v));} }
static class CodexAppServerQuotaCollector { public static QuotaValues FetchQuota(){try{return FetchAppServer();}catch(Exception ex){Log.Append("quota-mxp.log","quota app-server direct failed: "+ex.Message);var q=FetchSessionQuota();if(q!=null)return q;throw;}} static QuotaValues FetchAppServer(){string codex=FindCodexExe();var psi=new ProcessStartInfo(codex,"app-server --stdio"){UseShellExecute=false,RedirectStandardInput=true,RedirectStandardOutput=true,RedirectStandardError=true,CreateNoWindow=true,StandardOutputEncoding=Encoding.UTF8,StandardErrorEncoding=Encoding.UTF8};if(string.IsNullOrWhiteSpace(Environment.GetEnvironmentVariable("CODEX_HOME")))psi.EnvironmentVariables["CODEX_HOME"]=Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),".codex");using(var p=new Process{StartInfo=psi}){string response=null,err="";var got=new AutoResetEvent(false);p.OutputDataReceived+=(s,e)=>{if(e.Data!=null&&e.Data.IndexOf("\"id\":2")>=0){response=e.Data;got.Set();}};p.ErrorDataReceived+=(s,e)=>{if(e.Data!=null)err+=e.Data+"\n";};if(!p.Start())throw new Exception("failed to start codex app-server: "+codex);p.BeginOutputReadLine();p.BeginErrorReadLine();p.StandardInput.WriteLine("{\"jsonrpc\":\"2.0\",\"id\":1,\"method\":\"initialize\",\"params\":{}}");p.StandardInput.WriteLine("{\"jsonrpc\":\"2.0\",\"method\":\"initialized\",\"params\":{}}");p.StandardInput.WriteLine("{\"jsonrpc\":\"2.0\",\"id\":2,\"method\":\"account/rateLimits/read\",\"params\":{}}");p.StandardInput.Flush();if(!got.WaitOne(15000))throw new Exception("codex app-server quota timeout "+err.Trim());try{if(!p.HasExited)p.Kill();}catch{}var q=Parse(response);if(q==null)throw new Exception("quota response did not contain 5h/weekly limits");return q;}} static string FindCodexExe(){string e=Environment.GetEnvironmentVariable("CODEX_EXE");if(File.Exists(e))return e;foreach(string dir in (Environment.GetEnvironmentVariable("PATH")??"").Split(';')){try{string p=Path.Combine(dir.Trim(),"codex.exe");if(File.Exists(p))return p;}catch{}}string alias=Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),"Microsoft","WindowsApps","codex.exe");if(File.Exists(alias))return alias;string root=Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.ProgramFiles),"WindowsApps");try{if(Directory.Exists(root)){FileInfo best=null;foreach(string f in Directory.GetFiles(root,"codex.exe",SearchOption.AllDirectories)){try{var i=new FileInfo(f);if(i.FullName.IndexOf("OpenAI.Codex",StringComparison.OrdinalIgnoreCase)>=0&&(best==null||i.LastWriteTimeUtc>best.LastWriteTimeUtc))best=i;}catch{}}if(best!=null)return best.FullName;}}catch{}return "codex";} class Limit { public int Duration; public double Used; }
  static QuotaValues Parse(string text){var obj=new JavaScriptSerializer().DeserializeObject(text);var list=new List<Limit>();Walk(obj,list);int? five=null,week=null;foreach(var l in list){int remaining=Clamp((int)Math.Round(100-l.Used));if(l.Duration==300)five=remaining;else if(l.Duration==10080)week=remaining;}return five.HasValue&&week.HasValue?new QuotaValues{FiveHour=five.Value,Weekly=week.Value}:null;} static void Walk(object obj,List<Limit> list){var d=obj as Dictionary<string,object>;if(d!=null){object dur,used;if((d.TryGetValue("windowDurationMins",out dur)||d.TryGetValue("window_minutes",out dur))&&(d.TryGetValue("usedPercent",out used)||d.TryGetValue("used_percent",out used))){try{list.Add(new Limit{Duration=Convert.ToInt32(dur),Used=Convert.ToDouble(used)});}catch{}}foreach(var v in d.Values)Walk(v,list);return;}var a=obj as object[];if(a!=null)foreach(var v in a)Walk(v,list);} static QuotaValues FetchSessionQuota(){string root=Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),".codex","sessions");if(!Directory.Exists(root))return null;var files=new List<FileInfo>();foreach(string f in Directory.GetFiles(root,"*.jsonl",SearchOption.AllDirectories)){try{files.Add(new FileInfo(f));}catch{}}files.Sort((a,b)=>b.LastWriteTimeUtc.CompareTo(a.LastWriteTimeUtc));for(int i=0;i<files.Count&&i<12;i++){foreach(string line in TailLines(files[i].FullName,900)){if(line.IndexOf("rate_limits",StringComparison.OrdinalIgnoreCase)<0)continue;try{var q=Parse(line);if(q!=null)return q;}catch{}}}return null;} static List<string> TailLines(string path,int maxLines){byte[] buf;using(var fs=new FileStream(path,FileMode.Open,FileAccess.Read,FileShare.ReadWrite)){long start=Math.Max(0,fs.Length-524288);fs.Seek(start,SeekOrigin.Begin);buf=new byte[fs.Length-start];fs.Read(buf,0,buf.Length);}string text=Encoding.UTF8.GetString(buf);var parts=text.Split(new[]{"\r\n","\n"},StringSplitOptions.RemoveEmptyEntries);var list=new List<string>();int startIndex=Math.Max(0,parts.Length-maxLines);for(int i=parts.Length-1;i>=startIndex;i--)list.Add(parts[i]);return list;} static int Clamp(int v){return Math.Max(0,Math.Min(100,v));} }static class ContextResolver { public static string TaskId(string ws,string sid,string tid){if(!string.IsNullOrWhiteSpace(tid))return tid;if(!string.IsNullOrWhiteSpace(sid))return sid;return "workspace-"+Math.Abs((ws??Environment.CurrentDirectory).ToLowerInvariant().GetHashCode()).ToString("x");} }
static class Log { public static void Append(string file,string line){try{Directory.CreateDirectory(StateStore.SupportDir());File.AppendAllText(Path.Combine(StateStore.SupportDir(),file),DateTime.UtcNow.ToString("o")+" "+line+Environment.NewLine,Encoding.UTF8);}catch{}} }
static class SessionFallbackMonitor {
  static Dictionary<string,string> lastDecisionByPath=new Dictionary<string,string>();
  static Dictionary<string,DateTime> lastWriteByPath=new Dictionary<string,DateTime>();
  static Dictionary<string,long> lastLengthByPath=new Dictionary<string,long>();
  public static bool TryUpdate(StateStore store,out StateSnapshot snap){snap=null;try{bool changed=false;StateSnapshot latest=null;foreach(string path in LatestSessionPaths(8)){FileInfo info;try{info=new FileInfo(path);}catch{continue;}DateTime w;long len;if(lastWriteByPath.TryGetValue(path,out w)&&lastLengthByPath.TryGetValue(path,out len)&&w==info.LastWriteTimeUtc&&len==info.Length)continue;lastWriteByPath[path]=info.LastWriteTimeUtc;lastLengthByPath[path]=info.Length;var d=Decide(path);if(d==null)continue;string prev;if(lastDecisionByPath.TryGetValue(path,out prev)&&prev==d.Key)continue;lastDecisionByPath[path]=d.Key;string taskId="session-"+StableHash(path);latest=store.UpdateTask(taskId,d.State,path,"session",d.EventName,d.Message);Log.Append("session-fallback.log","event="+d.EventName+" state="+d.State+" task="+taskId+" file="+Path.GetFileName(path));changed=true;}if(!changed)return false;snap=latest??store.Read();return true;}catch(Exception ex){Log.Append("session-fallback.log","error "+ex.Message);return false;}}
  class Decision { public LightState State; public string EventName,Message,Key; }
  static List<string> LatestSessionPaths(int max){var r=new List<string>();string root=Path.Combine(CodexHome(),"sessions");if(!Directory.Exists(root))return r;var files=new List<FileInfo>();foreach(var f in Directory.GetFiles(root,"*.jsonl",SearchOption.AllDirectories)){try{files.Add(new FileInfo(f));}catch{}}files.Sort((a,b)=>b.LastWriteTimeUtc.CompareTo(a.LastWriteTimeUtc));for(int i=0;i<files.Count&&i<max;i++)r.Add(files[i].FullName);return r;}
  static Decision Decide(string path){var lines=TailLines(path,620);Decision working=null;var completed=new HashSet<string>();for(int i=lines.Count-1;i>=0;i--){string line=lines[i];if(HasField(line,"type","task_complete")||HasField(line,"phase","final_answer"))return New(LightState.done,"task_complete","Codex traffic light: done",line);if(HasField(line,"type","task_started")||HasField(line,"type","user_message"))return working??New(LightState.working,"task_started","Codex traffic light: working",line);if(HasField(line,"type","function_call_output")){string cid=CallId(line);if(!string.IsNullOrWhiteSpace(cid))completed.Add(cid);if(working==null)working=New(LightState.working,"tool_output","Codex traffic light: working",line);continue;}if(HasField(line,"type","function_call")){if(IsPendingUserInputCall(line,completed))return New(LightState.waiting,"user_input_request","Codex traffic light: waiting",line);if(working==null)working=New(LightState.working,"tool_call","Codex traffic light: working",line);continue;}}return working;}  static bool IsPendingUserInputCall(string line,HashSet<string> completed){if(string.IsNullOrWhiteSpace(line))return false;if(!HasField(line,"type","function_call"))return false;try{var payload=Payload(line);string n=NameOf(payload)??Field(line,"name");if(n=="request_user_input"||n=="tool_call_approval")return true;if(n=="shell_command"&&IsEscalatedShell(payload)){string cid=CallId(payload);if(string.IsNullOrWhiteSpace(cid))cid=CallId(line);return string.IsNullOrWhiteSpace(cid)||!completed.Contains(cid);}}catch{}return false;} static bool HasField(string line,string name,string value){return Regex.IsMatch(line,"\\\""+Regex.Escape(name)+"\\\"\\s*:\\s*\\\""+Regex.Escape(value)+"\\\"");} static string Field(string line,string name){var m=Regex.Match(line,"\\\""+Regex.Escape(name)+"\\\"\\s*:\\s*\\\"([^\\\"]+)\\\"");return m.Success?m.Groups[1].Value:null;} static string NameOf(Dictionary<string,object> payload){object type,name;if(payload!=null&&payload.TryGetValue("type",out type)&&Convert.ToString(type)=="function_call"&&payload.TryGetValue("name",out name))return Convert.ToString(name);return null;} static bool IsEscalatedShell(Dictionary<string,object> payload){try{object a;if(payload==null||!payload.TryGetValue("arguments",out a)||a==null)return false;var args=Convert.ToString(a);var d=new JavaScriptSerializer().DeserializeObject(args) as Dictionary<string,object>;object v;if(d!=null&&d.TryGetValue("sandbox_permissions",out v)&&Convert.ToString(v)=="require_escalated")return true;}catch{}return false;} static Dictionary<string,object> Payload(string line){var root=new JavaScriptSerializer().DeserializeObject(line) as Dictionary<string,object>;if(root==null)return null;object p;if(root.TryGetValue("payload",out p))return p as Dictionary<string,object>;return root;} static string CallId(string line){try{string cid=Field(line,"call_id");if(!string.IsNullOrWhiteSpace(cid))return cid;return CallId(Payload(line));}catch{return null;}} static string CallId(Dictionary<string,object> payload){object v;if(payload==null)return null;if(payload.TryGetValue("call_id",out v)&&v!=null)return Convert.ToString(v);if(payload.TryGetValue("id",out v)&&v!=null)return Convert.ToString(v);return null;}  static Decision New(LightState s,string ev,string msg,string raw){return new Decision{State=s,EventName=ev,Message=msg,Key=ev+":"+StableHash(raw)};}
  static string StableHash(string s){using(var sha=System.Security.Cryptography.SHA1.Create()){var b=sha.ComputeHash(Encoding.UTF8.GetBytes(s??""));return BitConverter.ToString(b,0,6).Replace("-","").ToLowerInvariant();}}
  static List<string> TailLines(string path,int maxLines){byte[] buf;using(var fs=new FileStream(path,FileMode.Open,FileAccess.Read,FileShare.ReadWrite)){long start=Math.Max(0,fs.Length-262144);fs.Seek(start,SeekOrigin.Begin);buf=new byte[fs.Length-start];fs.Read(buf,0,buf.Length);}string text=Encoding.UTF8.GetString(buf);var parts=text.Split(new[]{"\r\n","\n"},StringSplitOptions.RemoveEmptyEntries);var list=new List<string>();int startIndex=Math.Max(0,parts.Length-maxLines);for(int i=startIndex;i<parts.Length;i++)list.Add(parts[i]);return list;}
  static string CodexHome(){string e=Environment.GetEnvironmentVariable("CODEX_HOME");return string.IsNullOrWhiteSpace(e)?Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),".codex"):e;}
