class Preferences { public bool Muted=false,AutoStart=false,AutoShowOnWaiting=true,AutoShowOnDone=true,ShowFloatingWindow=true; public int Volume=80; }
class PreferencesStore { string PathName; JavaScriptSerializer json=new JavaScriptSerializer(); public PreferencesStore(){PathName=Path.Combine(StateStore.SupportDir(),"preferences.json");} public Preferences Read(){try{if(!File.Exists(PathName))return Defaults();var d=json.Deserialize<Dictionary<string,object>>(File.ReadAllText(PathName,Encoding.UTF8));var p=Defaults();object v;if(d.TryGetValue("muted",out v))p.Muted=Convert.ToBoolean(v);if(d.TryGetValue("auto_start",out v))p.AutoStart=Convert.ToBoolean(v);if(d.TryGetValue("auto_show_on_waiting",out v))p.AutoShowOnWaiting=Convert.ToBoolean(v);if(d.TryGetValue("auto_show_on_done",out v))p.AutoShowOnDone=Convert.ToBoolean(v);if(d.TryGetValue("show_floating_window",out v))p.ShowFloatingWindow=Convert.ToBoolean(v);if(d.TryGetValue("volume",out v))p.Volume=Math.Max(0,Math.Min(100,Convert.ToInt32(v)));return p;}catch{return Defaults();}} public void Write(Preferences p){try{Directory.CreateDirectory(System.IO.Path.GetDirectoryName(PathName));var d=new Dictionary<string,object>{{"muted",p.Muted},{"auto_start",p.AutoStart},{"auto_show_on_waiting",p.AutoShowOnWaiting},{"auto_show_on_done",p.AutoShowOnDone},{"show_floating_window",p.ShowFloatingWindow},{"volume",p.Volume}};File.WriteAllText(PathName,json.Serialize(d),Encoding.UTF8);}catch(Exception ex){Log.Append("windows-error.log","preferences failed: "+ex.Message);}} Preferences Defaults(){return new Preferences{AutoStart=StartupManager.IsEnabled()};} }static class StartupManager { const string Name="红绿灯"; public static bool IsEnabled(){try{using(var k=Registry.CurrentUser.OpenSubKey(@"Software\Microsoft\Windows\CurrentVersion\Run",false)){return k!=null&&k.GetValue(Name)!=null;}}catch{return false;}} public static void Set(bool enabled){try{using(var k=Registry.CurrentUser.OpenSubKey(@"Software\Microsoft\Windows\CurrentVersion\Run",true)??Registry.CurrentUser.CreateSubKey(@"Software\Microsoft\Windows\CurrentVersion\Run")){if(enabled)k.SetValue(Name,"\""+Application.ExecutablePath+"\"");else k.DeleteValue(Name,false);}}catch(Exception ex){Log.Append("windows-error.log","startup failed: "+ex.Message);}} }
static class AlertSound { [DllImport("winmm.dll",CharSet=CharSet.Unicode)] static extern int mciSendString(string command,StringBuilder buffer,int bufferSize,IntPtr hwndCallback); public static void Play(LightState st,int volume){string file=Find(st==LightState.waiting?"红灯.wav":st==LightState.done?"绿灯.wav":null);if(string.IsNullOrWhiteSpace(file)){if(st==LightState.waiting)SystemSounds.Exclamation.Play();else if(st==LightState.done)SystemSounds.Asterisk.Play();return;}ThreadPool.QueueUserWorkItem(_=>{string a="codexlight"+Guid.NewGuid().ToString("N");try{int v=Math.Max(0,Math.Min(100,volume))*10;mciSendString("open \""+file+"\" type waveaudio alias "+a,null,0,IntPtr.Zero);mciSendString("setaudio "+a+" volume to "+v,null,0,IntPtr.Zero);mciSendString("play "+a+" wait",null,0,IntPtr.Zero);}catch{try{new SoundPlayer(file).Play();}catch{}}finally{try{mciSendString("close "+a,null,0,IntPtr.Zero);}catch{}}});} static string Find(string name){if(string.IsNullOrWhiteSpace(name))return null;string d=Application.StartupPath;for(int i=0;i<4&&d!=null;i++){string p=Path.Combine(d,name);if(File.Exists(p))return p;d=Directory.GetParent(d)==null?null:Directory.GetParent(d).FullName;}return null;} }
