class TrafficLightApp:Form { StateStore store=new StateStore(); PreferencesStore prefStore=new PreferencesStore(); TrafficLightControl view=new TrafficLightControl(); System.Windows.Forms.Timer poll=new System.Windows.Forms.Timer(),blink=new System.Windows.Forms.Timer(),waitStop=new System.Windows.Forms.Timer(),quotaTimer=new System.Windows.Forms.Timer(),doneFlash=new System.Windows.Forms.Timer(); NotifyIcon tray; Preferences pref; LightState state=LightState.idle,realState=LightState.idle; QuotaSnapshot quota; DateTime lastWrite=DateTime.MinValue; bool quotaBusy,doneFlashActive; Point drag; ToolTip tips=new ToolTip(); bool refreshHover; Dictionary<string,DateTime> seenDone=new Dictionary<string,DateTime>(); Dictionary<string,LightState> knownTaskStates=new Dictionary<string,LightState>(); Panel settingsPanel; CheckBox autoStartBox; TrackBar volumeBar; Label volumeValue;
