  void PollState(){StateSnapshot fb;if(SessionFallbackMonitor.TryUpdate(store,out fb)){lastWrite=DateTime.MinValue;HandleSnapshot(fb,true);return;}DateTime mod=File.Exists(store.StatePath)?File.GetLastWriteTimeUtc(store.StatePath):DateTime.MinValue;if(mod==lastWrite)return;lastWrite=mod;HandleSnapshot(store.Read(),true);} void HandleSnapshot(StateSnapshot sn,bool sound){quota=sn.Quota;if(sn.AggregateState==LightState.quit){Close();return;}realState=sn.AggregateState;if(realState==LightState.waiting&&doneFlashActive){doneFlash.Stop();doneFlashActive=false;}if(MaybeFlashDone(sn))return;if(doneFlashActive){UpdateOnly();return;}if(realState!=state)Apply(realState,sound,false);else UpdateOnly();} bool MaybeFlashDone(StateSnapshot sn){DateTime now=DateTime.UtcNow;bool shouldFlash=false;foreach(var p in sn.Tasks){var t=p.Value;LightState prevState;bool known=knownTaskStates.TryGetValue(p.Key,out prevState);DateTime prevDone;if(t.State==LightState.done&&known&&prevState!=LightState.done&&(!seenDone.TryGetValue(p.Key,out prevDone)||prevDone<t.UpdatedAt)&&(now-t.UpdatedAt).TotalSeconds<=8&&sn.AggregateState!=LightState.done){shouldFlash=true;seenDone[p.Key]=t.UpdatedAt;}knownTaskStates[p.Key]=t.State;if(t.State==LightState.done&&!seenDone.ContainsKey(p.Key))seenDone[p.Key]=t.UpdatedAt;}if(shouldFlash){FlashDone();return true;}return false;} void FlashDone(){doneFlash.Stop();doneFlashActive=true;Apply(LightState.done,true,false);doneFlash.Start();} void MarkKnownTasks(StateSnapshot sn){foreach(var p in sn.Tasks){knownTaskStates[p.Key]=p.Value.State;if(p.Value.State==LightState.done)seenDone[p.Key]=p.Value.UpdatedAt;}}
  void Manual(LightState st){var sn=store.UpdateTask("manual",st,Environment.CurrentDirectory,"menu",null,"Codex traffic light: "+st);quota=sn.Quota;realState=sn.AggregateState;knownTaskStates["manual"]=st;if(st==LightState.done)seenDone["manual"]=DateTime.UtcNow;Apply(sn.AggregateState,true,true);}
  void Apply(LightState st,bool sound,bool user){state=st;view.State=st;view.Quota=quota;if(st==LightState.waiting){view.WaitingAlertActive=true;view.BlinkOn=true;waitStop.Stop();waitStop.Start();}else{waitStop.Stop();view.WaitingAlertActive=false;view.BlinkOn=true;}view.Invalidate();view.Update();tray.Icon=Icon.FromHandle(TrayBitmap(st).GetHicon());tray.Text="红绿灯："+StateText.Label(st)+" "+QuotaText(quota);RebuildMenu();bool show=user||(st==LightState.waiting&&pref.AutoShowOnWaiting)||(st==LightState.done&&pref.AutoShowOnDone)||(Visible&&pref.ShowFloatingWindow);if(show&&pref.ShowFloatingWindow){Show();Activate();BringToFront();view.Update();}if(sound&&!pref.Muted){if(st==LightState.waiting||st==LightState.done)AlertSound.Play(st,pref.Volume);}}
