  protected override void OnFormClosing(FormClosingEventArgs e){CleanupTray();base.OnFormClosing(e);} protected override void OnFormClosed(FormClosedEventArgs e){CleanupTray();base.OnFormClosed(e);} void CleanupTray(){try{if(tray!=null){tray.Visible=false;tray.ContextMenuStrip=null;tray.Icon=null;tray.Dispose();tray=null;}}catch{}} static string QuotaText(QuotaSnapshot q){return q==null?"暂无数据":"5小时 "+q.FiveHourRemainingPercent+"% · 1周 "+q.WeeklyRemainingPercent+"%";} static string HookStatusText(){try{string p=Path.Combine(StateStore.SupportDir(),"hook-mxp.log");if(!File.Exists(p))return "Hooks：未触发/未安装";DateTime t=File.GetLastWriteTime(p);string last="";using(var fs=new FileStream(p,FileMode.Open,FileAccess.Read,FileShare.ReadWrite))using(var sr=new StreamReader(fs,Encoding.UTF8)){string line;while((line=sr.ReadLine())!=null){line=line.Trim();if(line.Length>0)last=line;}}if(last.Length>72)last=last.Substring(0,72)+"...";return "Hooks：最近 "+t.ToString("HH:mm:ss")+(last.Length>0?" · "+last:" ");}catch{return "Hooks：状态未知";}}
