  void MacControls(Graphics g){MacDot(g,17,16,Color.FromArgb(255,95,86));MacDot(g,32,16,Color.FromArgb(255,189,46));MacDot(g,47,16,Color.FromArgb(39,201,63));} void MacDot(Graphics g,int x,int y,Color c){using(var br=new SolidBrush(c))g.FillEllipse(br,x-4,y-4,8,8);using(var pen=new Pen(Color.FromArgb(65,0,0,0),1))g.DrawEllipse(pen,x-4,y-4,8,8);} void Title(Graphics g){using(var f=new Font("Segoe UI",9f,FontStyle.Bold))using(var b=new SolidBrush(Color.FromArgb(126,255,255,255)))using(var sf=new StringFormat{Alignment=StringAlignment.Far})g.DrawString("Codex",f,b,new RectangleF(154,10,48,16),sf);}
  void StatusQuota(Graphics g){using(var f=new Font("Microsoft YaHei UI",7.6f))using(var b=new SolidBrush(Color.FromArgb(150,255,255,255)))using(var sf=new StringFormat{Alignment=StringAlignment.Center})g.DrawString(StateText.Label(State),f,b,new RectangleF(14,58,Width-28,12),sf);QuotaRow(g,"5小时",Quota==null?(int?)null:Quota.FiveHourRemainingPercent,78,Color.FromArgb(97,214,199));QuotaRow(g,"1周",Quota==null?(int?)null:Quota.WeeklyRemainingPercent,94,Color.FromArgb(139,217,107));}
  void QuotaRow(Graphics g,string label,int? percent,int y,Color accent){int left=26,labelW=62,gap=8;int x=left+labelW+gap,w=Width-x-26;string val=percent.HasValue?Math.Max(0,Math.Min(100,percent.Value))+"%":"--";using(var f=new Font("Microsoft YaHei UI",6.8f,FontStyle.Bold))using(var b=new SolidBrush(Color.FromArgb(percent.HasValue?174:108,255,255,255)))using(var sf=new StringFormat{Alignment=StringAlignment.Far,LineAlignment=StringAlignment.Center})g.DrawString(label+" "+val,f,b,new RectangleF(left,y-7,labelW,12),sf);using(var tr=new SolidBrush(Color.FromArgb(34,255,255,255)))g.FillRectangle(tr,x,y,w,3);if(percent.HasValue&&percent.Value>0)using(var fl=new SolidBrush(Color.FromArgb(190,accent)))g.FillRectangle(fl,x,y,w*Math.Max(0,Math.Min(100,percent.Value))/100,3);}
  void Lens(Graphics g,PointF c,Color col,bool on){using(var glow=new SolidBrush(Color.FromArgb(on?66:10,col)))g.FillEllipse(glow,c.X-18,c.Y-18,36,36);using(var br=new SolidBrush(Color.FromArgb(on?255:48,col)))g.FillEllipse(br,c.X-12,c.Y-12,24,24);using(var rim=new Pen(Color.FromArgb(on?112:34,col),3))g.DrawEllipse(rim,c.X-12,c.Y-12,24,24);using(var dark=new Pen(Color.FromArgb(58,0,0,0),1))g.DrawEllipse(dark,c.X-12,c.Y-12,24,24);using(var hi=new SolidBrush(Color.FromArgb(on?62:18,255,255,255)))g.FillEllipse(hi,c.X-5,c.Y-8,10,4);}
  static GraphicsPath Round(Rectangle r,int rad){return RoundRect(r,rad);} public static GraphicsPath RoundRect(Rectangle r,int rad){int d=rad*2;var p=new GraphicsPath();p.AddArc(r.X,r.Y,d,d,180,90);p.AddArc(r.Right-d,r.Y,d,d,270,90);p.AddArc(r.Right-d,r.Bottom-d,d,d,0,90);p.AddArc(r.X,r.Bottom-d,d,d,90,90);p.CloseFigure();return p;}
}
